/*
 * Charts are rendered as SVG and inserted into the worksheet as a picture
 * Shape. This is the same architectural pattern ThinkCell uses internally
 * (render to vector, drop into the host as an image) — it avoids the
 * limitations of Excel's native chart types.
 *
 * Each shape carries a name like "SharpCell.<chartType>.<short-id>" so the
 * binding registry can find it again and replace it on refresh.
 */

/* global Excel */

import { BindingRegistry, ChartType, RegisteredBinding } from "../core/bindings";
import { RangeSnapshot } from "../core/data";

const SHAPE_PREFIX = "SharpCell";

export function makeShapeName(chartType: ChartType): string {
  const stamp = Math.random().toString(36).slice(2, 8);
  return `${SHAPE_PREFIX}.${chartType}.${stamp}`;
}

/**
 * Insert (or replace) a shape containing the given SVG. If a binding is
 * provided, the shape is named after the binding and any existing shape
 * with the same name is removed first (this is the "refresh" path).
 *
 * Returns the final shape name.
 */
export async function upsertSvgShape(
  svg: string,
  chartType: ChartType,
  source: RangeSnapshot,
  existing?: RegisteredBinding
): Promise<RegisteredBinding> {
  const shapeName = existing?.shapeName ?? makeShapeName(chartType);

  // base64 encode the SVG for insertion as a picture
  const base64 = svgToBase64(svg);

  return Excel.run(async (ctx) => {
    const sheet = ctx.workbook.worksheets.getActiveWorksheet();
    const shapes = sheet.shapes;
    shapes.load("items/name");
    await ctx.sync();

    // Remove existing shape with this name (refresh path)
    let priorLeft = 40;
    let priorTop = 40;
    let priorWidth = 480;
    let priorHeight = 300;
    const prior = shapes.items.find((s) => s.name === shapeName);
    if (prior) {
      prior.load(["left", "top", "width", "height"]);
      await ctx.sync();
      priorLeft = prior.left;
      priorTop = prior.top;
      priorWidth = prior.width;
      priorHeight = prior.height;
      prior.delete();
      await ctx.sync();
    }

    // Insert new picture from SVG
    const image = shapes.addImage(base64);
    image.name = shapeName;
    image.left = priorLeft;
    image.top = priorTop;
    image.width = priorWidth;
    image.height = priorHeight;
    await ctx.sync();

    // Persist binding
    if (existing) {
      await BindingRegistry.update(existing.id, {
        rangeAddress: source.address,
        sheetName: source.sheetName,
      });
      return existing;
    }
    return BindingRegistry.add({
      chartType,
      shapeName,
      sheetName: source.sheetName,
      rangeAddress: source.address,
    });
  });
}

function svgToBase64(svg: string): string {
  // Office's addImage expects base64 of an image. SVG works in Excel desktop;
  // for the web we additionally wrap it for broad compatibility.
  const utf8 = unescape(encodeURIComponent(svg));
  return btoa(utf8);
}
