/*
 * Stacked column chart with segment totals printed above each column.
 *
 * Same input layout as Mekko:
 *   [Category]  [S1]  [S2]  [S3]
 *   "2024"       100   60    40
 *   "2025"       110   70    35
 */

import { readActiveSelection, parseTable, RangeSnapshot } from "../core/data";
import { activePalette } from "../core/style";
import {
  openSvg,
  closeSvg,
  title,
  rect,
  text,
  line,
  formatNumber,
  niceTicks,
  DEFAULT_SIZE,
  DEFAULT_MARGINS,
  seriesColor,
} from "./svgPrimitives";
import { upsertSvgShape } from "./svgHost";
import { RegisteredBinding } from "../core/bindings";

export function renderStackedWithTotalsSvg(snap: RangeSnapshot, opts?: { titleText?: string }): string {
  const parsed = parseTable(snap);
  const palette = activePalette();
  const { width, height } = DEFAULT_SIZE;
  const m = { ...DEFAULT_MARGINS };
  const plotW = width - m.left - m.right;
  const plotH = height - m.top - m.bottom;

  const maxTotal = Math.max(...parsed.totals.row);
  const ticks = niceTicks(0, maxTotal, 6);
  const yOf = (v: number) => m.top + plotH - (v / ticks.max) * plotH;

  const slotW = plotW / parsed.categories.length;
  const barW = slotW * 0.6;

  let svg = openSvg();
  svg += title(opts?.titleText ?? "Stacked + totals", { width, height });

  ticks.ticks.forEach((t) => {
    const y = yOf(t);
    svg += line(m.left, y, m.left + plotW, y, "#EEE");
    svg += text(m.left - 6, y + 3, formatNumber(t), { anchor: "end", fill: "#666" });
  });

  parsed.categories.forEach((cat, i) => {
    const cx = m.left + slotW * i + slotW / 2;
    const bx = cx - barW / 2;
    let yCursor = m.top + plotH;
    parsed.matrix[i].forEach((v, sIdx) => {
      const h = (v / ticks.max) * plotH;
      yCursor -= h;
      svg += rect(bx, yCursor, barW, h, seriesColor(sIdx, palette));
      if (h > 14) {
        svg += text(cx, yCursor + h / 2 + 3, formatNumber(v), { fill: "white", weight: "600" });
      }
    });
    // total label above bar
    svg += text(cx, yOf(parsed.totals.row[i]) - 6, formatNumber(parsed.totals.row[i]), {
      weight: "700",
      size: 12,
      fill: "#1A1A1A",
    });
    // category label
    svg += text(cx, m.top + plotH + 18, cat, { size: 10 });
  });

  // legend
  const legendY = m.top + plotH + 36;
  let lx = m.left;
  parsed.series.forEach((s, i) => {
    svg += rect(lx, legendY, 10, 10, seriesColor(i, palette));
    svg += text(lx + 14, legendY + 9, s, { anchor: "start", size: 10 });
    lx += 14 + s.length * 6 + 16;
  });

  svg += closeSvg();
  return svg;
}

export async function insertStackedWithTotals(): Promise<void> {
  const snap = await readActiveSelection();
  const svg = renderStackedWithTotalsSvg(snap);
  await upsertSvgShape(svg, "stackedTotals", snap);
}

export async function renderStackedWithTotals(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  const svg = renderStackedWithTotalsSvg(snap);
  await upsertSvgShape(svg, "stackedTotals", snap, binding);
}
