import * as React from "react";
import { useStatus } from "../StatusBar";
import { BindingRegistry, RegisteredBinding } from "../../core/bindings";
import { refreshBinding, refreshAllBindings } from "../../core/refresh";

export const BindingsPanel: React.FC = () => {
  const { setMessage } = useStatus();
  const [items, setItems] = React.useState<RegisteredBinding[]>([]);

  const reload = React.useCallback(async () => {
    setItems(await BindingRegistry.list());
  }, []);

  React.useEffect(() => {
    void reload();
  }, [reload]);

  const handleRefreshAll = async () => {
    try {
      setMessage("Refreshing all bindings...");
      const n = await refreshAllBindings();
      setMessage(`Refreshed ${n} binding(s).`);
    } catch (e) {
      setMessage(`Error: ${e instanceof Error ? e.message : String(e)}`);
    }
  };

  const handleRemove = async (id: string) => {
    await BindingRegistry.remove(id);
    await reload();
    setMessage("Binding removed.");
  };

  const handleRefresh = async (b: RegisteredBinding) => {
    try {
      setMessage(`Refreshing ${b.shapeName}...`);
      await refreshBinding(b);
      setMessage("Refreshed.");
    } catch (e) {
      setMessage(`Error: ${e instanceof Error ? e.message : String(e)}`);
    }
  };

  return (
    <>
      <section className="sc-section">
        <h2>Linked charts</h2>
        <p style={{ fontSize: 12, color: "var(--sc-muted)", marginTop: 0 }}>
          Every SharpCell chart is bound to its source range and re-renders when data changes.
        </p>
        <button className="sc-btn primary" onClick={handleRefreshAll}>
          Refresh all
        </button>
      </section>

      <section className="sc-section">
        <h2>Active bindings</h2>
        {items.length === 0 ? (
          <p style={{ fontSize: 12, color: "var(--sc-muted)" }}>No bindings yet. Insert a chart to create one.</p>
        ) : (
          <ul className="sc-bindings">
            {items.map((b) => (
              <li key={b.id}>
                <div>
                  <div style={{ fontWeight: 600 }}>{b.shapeName}</div>
                  <div style={{ color: "var(--sc-muted)", fontSize: 11 }}>
                    {b.chartType} · {b.rangeAddress}
                  </div>
                </div>
                <div>
                  <button className="sc-btn" style={{ width: "auto" }} onClick={() => handleRefresh(b)}>
                    Refresh
                  </button>
                  <button className="remove" onClick={() => handleRemove(b.id)} title="Remove binding">
                    ×
                  </button>
                </div>
              </li>
            ))}
          </ul>
        )}
      </section>
    </>
  );
};
