import * as React from "react";
import { useStatus } from "../StatusBar";
import { insertWaterfall } from "../../charts/waterfall";
import { insertMekko } from "../../charts/mekko";
import { insertGantt } from "../../charts/gantt";
import { insertButterfly } from "../../charts/butterfly";
import { insertStackedWithTotals } from "../../charts/stackedTotals";

interface ChartCard {
  id: string;
  label: string;
  icon: string;
  desc: string;
  handler: () => Promise<void>;
}

export const ChartsPanel: React.FC = () => {
  const { setMessage } = useStatus();

  const run = (fn: () => Promise<void>) => async () => {
    try {
      setMessage("Working...");
      await fn();
      setMessage("Done.");
    } catch (e) {
      const err = e instanceof Error ? e.message : String(e);
      setMessage(`Error: ${err}`);
    }
  };

  const cards: ChartCard[] = [
    {
      id: "waterfall",
      label: "Waterfall",
      icon: "WF",
      desc: "Bridge/cascade with totals and connectors",
      handler: insertWaterfall,
    },
    {
      id: "mekko",
      label: "Mekko",
      icon: "MK",
      desc: "Marimekko with variable column widths",
      handler: insertMekko,
    },
    { id: "gantt", label: "Gantt", icon: "GT", desc: "Project timeline (task, start, duration)", handler: insertGantt },
    {
      id: "butterfly",
      label: "Butterfly",
      icon: "BF",
      desc: "Mirrored bars for comparison",
      handler: insertButterfly,
    },
    {
      id: "stacked",
      label: "Stacked + totals",
      icon: "ST",
      desc: "Stacked columns with segment totals on top",
      handler: insertStackedWithTotals,
    },
  ];

  return (
    <>
      <section className="sc-section">
        <h2>Insert chart</h2>
        <p style={{ fontSize: 12, color: "var(--sc-muted)", marginTop: 0 }}>
          Select your source range, then click a chart type.
        </p>
        <div className="sc-grid">
          {cards.map((c) => (
            <button key={c.id} className="sc-card" onClick={run(c.handler)}>
              <span className="icon">{c.icon}</span>
              <span className="label">{c.label}</span>
              <span className="desc">{c.desc}</span>
            </button>
          ))}
        </div>
      </section>
    </>
  );
};
