/*
 * Butterfly (tornado) chart — two series mirrored around a center axis.
 *
 * Input range layout:
 *   [Category]   [LeftSeries]   [RightSeries]
 *   "25-34"        420             510
 *   "35-44"        380             460
 *   ...
 */

import { readActiveSelection, parseTable, RangeSnapshot } from "../core/data";
import { activePalette } from "../core/style";
import {
  openSvg,
  closeSvg,
  title,
  rect,
  text,
  line,
  formatNumber,
  DEFAULT_SIZE,
  DEFAULT_MARGINS,
} from "./svgPrimitives";
import { upsertSvgShape } from "./svgHost";
import { RegisteredBinding } from "../core/bindings";

export function renderButterflySvg(snap: RangeSnapshot, opts?: { titleText?: string }): string {
  const parsed = parseTable(snap);
  if (parsed.series.length < 2) throw new Error("Butterfly needs two value columns.");
  const palette = activePalette();
  const { width, height } = DEFAULT_SIZE;
  const m = { ...DEFAULT_MARGINS, left: 80, right: 80 };
  const plotW = width - m.left - m.right;
  const plotH = height - m.top - m.bottom;

  const half = plotW / 2;
  const centerX = m.left + half;
  const maxAbs = Math.max(
    ...parsed.matrix.map((row) => Math.max(Math.abs(row[0]) || 0, Math.abs(row[1]) || 0))
  );
  const scale = half / (maxAbs || 1);
  const barH = plotH / parsed.categories.length;
  const barInnerH = Math.min(24, barH * 0.7);

  let svg = openSvg();
  svg += title(opts?.titleText ?? "Butterfly", { width, height });

  // Center axis
  svg += line(centerX, m.top, centerX, m.top + plotH, "#999");

  parsed.categories.forEach((cat, i) => {
    const y = m.top + i * barH + (barH - barInnerH) / 2;
    const left = parsed.matrix[i][0] || 0;
    const right = parsed.matrix[i][1] || 0;
    const lw = left * scale;
    const rw = right * scale;
    svg += rect(centerX - lw, y, lw, barInnerH, palette.colors[0]);
    svg += rect(centerX, y, rw, barInnerH, palette.colors[1]);

    // Value labels at the bar tips
    svg += text(centerX - lw - 4, y + barInnerH / 2 + 3, formatNumber(left), {
      anchor: "end",
      size: 10,
      fill: "#333",
    });
    svg += text(centerX + rw + 4, y + barInnerH / 2 + 3, formatNumber(right), {
      anchor: "start",
      size: 10,
      fill: "#333",
    });

    // Center category label
    svg += text(centerX, y - 2, cat, { size: 10, fill: "#333" });
  });

  // Series legend
  const legendY = m.top + plotH + 26;
  svg += rect(centerX - 110, legendY, 10, 10, palette.colors[0]);
  svg += text(centerX - 96, legendY + 9, parsed.series[0], { anchor: "start", size: 10 });
  svg += rect(centerX + 20, legendY, 10, 10, palette.colors[1]);
  svg += text(centerX + 34, legendY + 9, parsed.series[1], { anchor: "start", size: 10 });

  svg += closeSvg();
  return svg;
}

export async function insertButterfly(): Promise<void> {
  const snap = await readActiveSelection();
  const svg = renderButterflySvg(snap);
  await upsertSvgShape(svg, "butterfly", snap);
}

export async function renderButterfly(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  const svg = renderButterflySvg(snap);
  await upsertSvgShape(svg, "butterfly", snap, binding);
}
