/*
 * Refresh logic: re-renders a chart from the latest source range data.
 * Also wires up a worksheet "onChanged" listener so SharpCell auto-refreshes
 * bindings whose source ranges overlap an edit.
 */

/* global Excel */

import { BindingRegistry, RegisteredBinding } from "./bindings";
import { readRange } from "./data";
import { renderWaterfall } from "../charts/waterfall";
import { renderMekko } from "../charts/mekko";
import { renderGantt } from "../charts/gantt";
import { renderButterfly } from "../charts/butterfly";
import { renderStackedWithTotals } from "../charts/stackedTotals";

export async function refreshBinding(b: RegisteredBinding): Promise<void> {
  const snap = await readRange(b.sheetName, stripSheetPrefix(b.rangeAddress, b.sheetName));
  switch (b.chartType) {
    case "waterfall":
      await renderWaterfall(snap, b);
      break;
    case "mekko":
      await renderMekko(snap, b);
      break;
    case "gantt":
      await renderGantt(snap, b);
      break;
    case "butterfly":
      await renderButterfly(snap, b);
      break;
    case "stackedTotals":
      await renderStackedWithTotals(snap, b);
      break;
  }
}

export async function refreshAllBindings(): Promise<number> {
  const items = await BindingRegistry.list();
  for (const b of items) {
    try {
      await refreshBinding(b);
    } catch (e) {
      // eslint-disable-next-line no-console
      console.warn(`SharpCell refresh failed for ${b.shapeName}`, e);
    }
  }
  return items.length;
}

function stripSheetPrefix(address: string, sheet: string): string {
  const prefix = `${sheet}!`;
  return address.startsWith(prefix) ? address.slice(prefix.length) : address;
}

/**
 * Wire up auto-refresh: every time a worksheet changes, check if any bound range
 * was touched. If so, refresh that binding. Call this once on add-in load.
 */
export async function installAutoRefresh(): Promise<void> {
  await Excel.run(async (ctx) => {
    const sheets = ctx.workbook.worksheets;
    sheets.load("items/name");
    await ctx.sync();
    sheets.items.forEach((sheet) => {
      sheet.onChanged.add(async (event) => {
        try {
          await handleSheetChange(sheet.name, event.address);
        } catch (e) {
          // eslint-disable-next-line no-console
          console.warn("SharpCell auto-refresh failed", e);
        }
      });
    });
    await ctx.sync();
  });
}

async function handleSheetChange(sheetName: string, changedAddress: string): Promise<void> {
  const bindings = await BindingRegistry.list();
  for (const b of bindings) {
    if (b.sheetName !== sheetName) continue;
    if (rangesIntersect(stripSheetPrefix(b.rangeAddress, sheetName), changedAddress)) {
      await refreshBinding(b);
    }
  }
}

/** Tiny A1-range intersection check. Accepts addresses like "A1:D8" (no sheet prefix). */
export function rangesIntersect(a: string, b: string): boolean {
  const ra = parseA1(a);
  const rb = parseA1(b);
  if (!ra || !rb) return false;
  return !(ra.endCol < rb.startCol || rb.endCol < ra.startCol || ra.endRow < rb.startRow || rb.endRow < ra.startRow);
}

interface A1 {
  startCol: number;
  endCol: number;
  startRow: number;
  endRow: number;
}

function parseA1(addr: string): A1 | null {
  const parts = addr.split(":");
  const a = cellToRC(parts[0]);
  const b = cellToRC(parts[1] ?? parts[0]);
  if (!a || !b) return null;
  return {
    startCol: Math.min(a.col, b.col),
    endCol: Math.max(a.col, b.col),
    startRow: Math.min(a.row, b.row),
    endRow: Math.max(a.row, b.row),
  };
}

function cellToRC(cell: string): { col: number; row: number } | null {
  const m = /^\$?([A-Z]+)\$?(\d+)$/i.exec(cell.trim());
  if (!m) return null;
  let col = 0;
  for (const ch of m[1].toUpperCase()) col = col * 26 + (ch.charCodeAt(0) - 64);
  return { col, row: parseInt(m[2], 10) };
}
