import * as React from "react";
import { useStatus } from "../StatusBar";
import { PALETTES, PaletteName, getActivePalette, setActivePalette } from "../../core/style";
import { applyCorporateStyle, cleanupChart } from "../../core/format";
import { addCagrArrow, addStackTotals } from "../../charts/annotations";

export const StylePanel: React.FC = () => {
  const { setMessage } = useStatus();
  const [palette, setPalette] = React.useState<PaletteName>(getActivePalette());

  const run = (fn: () => Promise<void>, label: string) => async () => {
    try {
      setMessage(`${label}...`);
      await fn();
      setMessage("Done.");
    } catch (e) {
      setMessage(`Error: ${e instanceof Error ? e.message : String(e)}`);
    }
  };

  const handlePalette = (name: PaletteName) => {
    setPalette(name);
    setActivePalette(name);
    setMessage(`Active palette: ${name}.`);
  };

  return (
    <>
      <section className="sc-section">
        <h2>Color palette</h2>
        <div className="sc-grid">
          {(Object.keys(PALETTES) as PaletteName[]).map((p) => (
            <button
              key={p}
              className="sc-card"
              onClick={() => handlePalette(p)}
              style={{ borderColor: p === palette ? "var(--sc-accent)" : undefined }}
            >
              <div>
                {PALETTES[p].colors.slice(0, 5).map((c, i) => (
                  <span key={i} className="sc-swatch" style={{ background: c }} />
                ))}
              </div>
              <span className="label">{p}</span>
              <span className="desc">{PALETTES[p].description}</span>
            </button>
          ))}
        </div>
      </section>

      <section className="sc-section">
        <h2>Apply to selected chart</h2>
        <button className="sc-btn primary" onClick={run(applyCorporateStyle, "Applying style")}>
          Apply corporate style
        </button>
        <div style={{ height: 6 }} />
        <button className="sc-btn" onClick={run(cleanupChart, "Cleaning")}>
          Clean up (remove gridlines, simplify axes)
        </button>
      </section>

      <section className="sc-section">
        <h2>Annotations</h2>
        <button className="sc-btn" onClick={run(addCagrArrow, "Adding CAGR arrow")}>
          Add CAGR arrow
        </button>
        <div style={{ height: 6 }} />
        <button className="sc-btn" onClick={run(addStackTotals, "Adding stack totals")}>
          Add stack totals
        </button>
      </section>
    </>
  );
};
